import { Conversation, Message, ApiResponse } from '@/types';
import { mockConversations, mockMessages, mockPatients, mockDoctors } from '@/data/mockData';
import { apiSuccess, apiError } from './api';

// In-memory stores
let conversations = [...mockConversations];
let messages = [...mockMessages];

export const chatService = {
  async getConversations(userId: string): Promise<ApiResponse<Conversation[]>> {
    const userConversations = conversations
      .filter(c => c.participants.includes(userId))
      .map(conv => {
        const lastMsg = messages
          .filter(m => m.conversationId === conv.id)
          .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())[0];
        
        return {
          ...conv,
          patient: mockPatients.find(p => p.id === conv.patientId),
          doctor: mockDoctors.find(d => d.id === conv.doctorId),
          lastMessage: lastMsg,
        };
      })
      .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());

    return apiSuccess(userConversations);
  },

  async getConversationById(conversationId: string): Promise<ApiResponse<Conversation | null>> {
    const conversation = conversations.find(c => c.id === conversationId);
    if (!conversation) {
      return apiError('Conversation not found');
    }

    return apiSuccess({
      ...conversation,
      patient: mockPatients.find(p => p.id === conversation.patientId),
      doctor: mockDoctors.find(d => d.id === conversation.doctorId),
    });
  },

  async getMessages(conversationId: string): Promise<ApiResponse<Message[]>> {
    const conversationMessages = messages
      .filter(m => m.conversationId === conversationId)
      .sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

    return apiSuccess(conversationMessages);
  },

  async sendMessage(
    conversationId: string,
    senderId: string,
    senderRole: 'patient' | 'doctor',
    content: string,
    type: 'text' | 'image' | 'file' | 'prescription' = 'text'
  ): Promise<ApiResponse<Message>> {
    const conversation = conversations.find(c => c.id === conversationId);
    if (!conversation) {
      return apiError('Conversation not found');
    }

    const newMessage: Message = {
      id: `msg-${Date.now()}`,
      conversationId,
      senderId,
      senderRole,
      content,
      type,
      isRead: false,
      timestamp: new Date().toISOString(),
    };

    messages.push(newMessage);

    // Update conversation
    const convIndex = conversations.findIndex(c => c.id === conversationId);
    conversations[convIndex] = {
      ...conversations[convIndex],
      updatedAt: new Date().toISOString(),
      unreadCount: conversations[convIndex].unreadCount + 1,
    };

    return apiSuccess(newMessage, 'Message sent');
  },

  async createConversation(
    patientId: string,
    doctorId: string
  ): Promise<ApiResponse<Conversation>> {
    // Check if conversation already exists
    const existing = conversations.find(
      c => c.patientId === patientId && c.doctorId === doctorId
    );

    if (existing) {
      return apiSuccess({
        ...existing,
        patient: mockPatients.find(p => p.id === patientId),
        doctor: mockDoctors.find(d => d.id === doctorId),
      });
    }

    const newConversation: Conversation = {
      id: `conv-${Date.now()}`,
      participants: [patientId, doctorId],
      patientId,
      doctorId,
      unreadCount: 0,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    conversations.push(newConversation);

    return apiSuccess({
      ...newConversation,
      patient: mockPatients.find(p => p.id === patientId),
      doctor: mockDoctors.find(d => d.id === doctorId),
    }, 'Conversation created');
  },

  async markAsRead(conversationId: string, userId: string): Promise<ApiResponse<void>> {
    const convIndex = conversations.findIndex(c => c.id === conversationId);
    if (convIndex === -1) {
      return apiError('Conversation not found');
    }

    // Mark all messages as read
    messages = messages.map(m => 
      m.conversationId === conversationId && m.senderId !== userId
        ? { ...m, isRead: true }
        : m
    );

    // Reset unread count
    conversations[convIndex] = {
      ...conversations[convIndex],
      unreadCount: 0,
    };

    return apiSuccess(undefined, 'Marked as read');
  },

  async getUnreadCount(userId: string): Promise<ApiResponse<number>> {
    const count = conversations
      .filter(c => c.participants.includes(userId))
      .reduce((sum, c) => sum + c.unreadCount, 0);

    return apiSuccess(count);
  },
};
